import{c as a,S as s,j as i,m as t}from"./chunks/framework.DvQr6YbT.js";const b=JSON.parse('{"title":"发布知识包","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/publish.md","filePath":"zh/sharing/publish.md","lastUpdated":1783414742000}'),n={name:"zh/sharing/publish.md"};function l(o,e,r,h,p,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="发布知识包" tabindex="-1">发布知识包 <a class="header-anchor" href="#发布知识包" aria-label="Permalink to “发布知识包”">​</a></h1><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drone-delivery</span></span></code></pre></div><p>从审核完成的范围到可分享的 URL，一条审慎的命令：</p><ol><li><strong>先过审核门</strong>——与 <code>bundle export</code> 同一道门。有任何未审项就打印清单，什么都 不会发布。</li><li>编译并打包（复用你上次导出的版本号）。</li><li>通过你自己的 <code>gh</code> 登录在配置的仓库里创建 GitHub Release，zip 作为资产。</li><li>你会得到一条可以直接转发的完整消息：资产 URL、它的 SHA-256，以及 <strong>谁能安装它</strong>——参见<a href="./grant-access">授权</a>。</li></ol><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Published jay.drone-delivery v0.1.0 to your-org/kb-bundles (private).</span></span>
<span class="line"><span>  Who can install: members with read access to your-org/kb-bundles (private).</span></span>
<span class="line"><span>  Grant access: your-org members with base Read permission already have it;</span></span>
<span class="line"><span>                invite others at https://github.com/your-org/kb-bundles/settings/access</span></span>
<span class="line"><span>  Share:  knowlery bundle install https://github.com/.../pack.zip --verify sha256-3f7a…</span></span></code></pre></div><h2 id="首次配置" tabindex="-1">首次配置 <a class="header-anchor" href="#首次配置" aria-label="Permalink to “首次配置”">​</a></h2><p>第一次发布需要指定目标仓库——传 <code>--repo owner/name</code>（或回答提示）。配置按知识包 记忆，之后发布无需再填。仓库不存在时，Knowlery 会提议以<strong>私有</strong>方式创建——把仓库 转公开是比发布一个 Release 更大的决定，留给你在 GitHub 上做。</p><p>在 Obsidian 里，导出对话框的结果页有同样的 &quot;Publish to GitHub&quot; 面板，共享同一份 记忆的配置。</p><h2 id="公开发布-第二道门" tabindex="-1">公开发布：第二道门 <a class="header-anchor" href="#公开发布-第二道门" aria-label="Permalink to “公开发布：第二道门”">​</a></h2><p>私有永远是默认。<code>--public</code> 会陈述一个额外的事实、问一个额外的问题：</p><blockquote><p>公开发布是永久的：缓存、镜像与爬虫会保留它，即使之后删除。</p></blockquote><p>如果任何<strong>已批准</strong>的条目带有风险提示（邮箱、凭证、私网 IP、人物页……），这些条目 会被重新列出并要求再次确认——你批准时想的是分享给同事，公开到互联网是另一个决定。 交互模式下输入 <code>publish</code> 确认；脚本和 agent 必须传 <code>--acknowledge-risks</code>，而 agent 的行为守则要求它只在向你完整展示清单、你明确同意之后才传。</p><p>这道门在<strong>每次</strong>公开发布时都会运行——对 v1.2 的同意不会静音 v1.3 的扫描，因为内容 变了，风险就变了。</p><div class="warning custom-block"><p class="custom-block-title">诚实的边界</p><p>模式扫描识别的是形状（API key、IP、手机号），不是含义。它无法知道某句话在商业上 敏感。逐条人工审核——真人读过每一页——才是真正的门。</p></div><h2 id="重新发布" tabindex="-1">重新发布 <a class="header-anchor" href="#重新发布" aria-label="Permalink to “重新发布”">​</a></h2><p>同一版本拒绝重复发布（必要时 <code>--force</code> 替换资产）。正常的更新流程：以新的 <code>--bundle-version</code> 重新导出，再发布——订阅者会看到新版本。</p><h2 id="没有-gh-时" tabindex="-1">没有 <code>gh</code> 时 <a class="header-anchor" href="#没有-gh-时" aria-label="Permalink to “没有 gh 时”">​</a></h2><p>发布配合 GitHub CLI 最顺（一条命令安装：<a href="https://cli.github.com" target="_blank" rel="noreferrer">cli.github.com</a>， 然后 <code>gh auth login</code>）。没有它时，<code>publish</code> 会打印完整的手动路径——zip 的位置、 精确的 <code>releases/new</code> 链接、要用的 tag、要随链接公布的 SHA-256——大约一分钟的 拖拽操作，产物与 gh 发布的完全等价。</p>`,18)])])}const g=a(n,[["render",l]]);export{b as __pageData,g as default};
